'use client'
import React, { useState } from 'react'

// Logos embedded as base64 — bypasses Vercel file-serving issues
const LOGO_MEDCLOUD_COLOR = "data:image/png;base64,"
const LOGO_MEDCLOUD_WHITE = "data:image/png;base64,"
const LOGO_COSENTUS_DIV_BLACK = "data:image/png;base64,"

export default function LoginPage() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)

  async function handleLogin(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)
    setError('')
    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      })
      const data = await res.json()
      if (res.ok) {
        localStorage.setItem('cosentus_region', data.country)
        localStorage.setItem('cosentus_portal_type', data.portalType)
        localStorage.setItem('cosentus_role', data.role)
        window.location.href = '/dashboard'
      } else {
        setError(data.error || 'Invalid email or password')
        setLoading(false)
      }
    } catch {
      setError('Network error — please try again')
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen flex">

      {/* ═══════════════════════════════
          LEFT — Login form (white)
      ═══════════════════════════════ */}
      <div className="flex-1 flex flex-col bg-white">

        {/* TOP-LEFT: MedCloud color logo */}
        <div className="flex justify-start px-10 pt-9">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={LOGO_MEDCLOUD_COLOR}
            alt="MedCloud"
            className="h-9 w-auto object-contain"
          />
        </div>

        {/* CENTER: Form — vertically + horizontally centered */}
        <div className="flex-1 flex items-center justify-center px-10 py-12">
          <div className="w-full max-w-[360px]">

            {/* Heading */}
            <div className="mb-9">
              <h2
                className="font-bold text-black tracking-tight leading-tight"
                style={{ fontSize: '28px', letterSpacing: '-0.02em' }}
              >
                Welcome back
              </h2>
              <p className="text-[14px] text-[#888] mt-2 font-normal">
                Sign in to your MedCloud account
              </p>
            </div>

            <form onSubmit={handleLogin} className="space-y-5">

              {/* Email */}
              <div className="space-y-1.5">
                <label className="text-[11px] font-semibold text-[#999] uppercase tracking-[0.08em] block">
                  Email Address
                </label>
                <input
                  type="email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  required
                  autoComplete="email"
                  autoFocus
                  placeholder="you@cosentus.com"
                  className="w-full rounded-[14px] px-4 py-[13px] text-[14px] text-black outline-none transition-all placeholder:text-[#C5C5C5]"
                  style={{
                    background: '#F7FBFD',
                    border: '1.5px solid #E2F0F5',
                    boxShadow: 'inset 0 1px 2px rgba(0,0,0,0.03)',
                  }}
                  onFocus={e => {
                    e.currentTarget.style.border = '1.5px solid #00B5D6'
                    e.currentTarget.style.boxShadow = '0 0 0 4px rgba(0,181,214,0.1), inset 0 1px 2px rgba(0,0,0,0.02)'
                    e.currentTarget.style.background = '#fff'
                  }}
                  onBlur={e => {
                    e.currentTarget.style.border = '1.5px solid #E2F0F5'
                    e.currentTarget.style.boxShadow = 'inset 0 1px 2px rgba(0,0,0,0.03)'
                    e.currentTarget.style.background = '#F7FBFD'
                  }}
                />
              </div>

              {/* Password */}
              <div className="space-y-1.5">
                <label className="text-[11px] font-semibold text-[#999] uppercase tracking-[0.08em] block">
                  Password
                </label>
                <input
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  required
                  autoComplete="current-password"
                  placeholder="••••••••••"
                  className="w-full rounded-[14px] px-4 py-[13px] text-[14px] text-black outline-none transition-all placeholder:text-[#C5C5C5]"
                  style={{
                    background: '#F7FBFD',
                    border: '1.5px solid #E2F0F5',
                    boxShadow: 'inset 0 1px 2px rgba(0,0,0,0.03)',
                  }}
                  onFocus={e => {
                    e.currentTarget.style.border = '1.5px solid #00B5D6'
                    e.currentTarget.style.boxShadow = '0 0 0 4px rgba(0,181,214,0.1), inset 0 1px 2px rgba(0,0,0,0.02)'
                    e.currentTarget.style.background = '#fff'
                  }}
                  onBlur={e => {
                    e.currentTarget.style.border = '1.5px solid #E2F0F5'
                    e.currentTarget.style.boxShadow = 'inset 0 1px 2px rgba(0,0,0,0.03)'
                    e.currentTarget.style.background = '#F7FBFD'
                  }}
                />
              </div>

              {/* Error */}
              {error && (
                <div className="text-[13px] text-[#065E76] bg-[#D6EBF2] border border-[#00B5D6]/20 rounded-[12px] px-4 py-3">
                  {error}
                </div>
              )}

              {/* Sign In button */}
              <button
                type="submit"
                disabled={loading}
                className="w-full text-white rounded-[14px] py-[14px] text-[14px] font-semibold transition-all disabled:opacity-50 active:scale-[0.98]"
                style={{
                  background: loading ? '#00B5D6' : 'linear-gradient(180deg, #17C2E0 0%, #00B5D6 100%)',
                  boxShadow: '0 1px 2px rgba(0,181,214,0.2), 0 4px 12px rgba(0,181,214,0.25)',
                  letterSpacing: '0.01em',
                }}
                onMouseEnter={e => {
                  if (!loading) (e.currentTarget.style.boxShadow = '0 1px 2px rgba(0,181,214,0.25), 0 6px 20px rgba(0,181,214,0.35)')
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.boxShadow = '0 1px 2px rgba(0,181,214,0.2), 0 4px 12px rgba(0,181,214,0.25)'
                }}
              >
                {loading ? (
                  <span className="flex items-center justify-center gap-2">
                    <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Signing in…
                  </span>
                ) : 'Sign In'}
              </button>
            </form>
          </div>
        </div>

        {/* BOTTOM-LEFT: A Cosentus Division (black on white) */}
        <div className="flex justify-start px-10 pb-9">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={LOGO_COSENTUS_DIV_BLACK}
            alt="A Cosentus Division"
            className="h-[13px] w-auto object-contain opacity-60"
          />
        </div>
      </div>

      {/* ═══════════════════════════════
          RIGHT — Brand blue panel
          Plain background, centered logo, division badge at bottom
      ═══════════════════════════════ */}
      <div
        className="hidden lg:flex w-[48%] shrink-0 flex-col items-center justify-center relative"
        style={{ background: '#00B5D6' }}
      >
        {/* Centered MedCloud white logo */}
        <div className="flex-1 flex items-center justify-center">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={LOGO_MEDCLOUD_WHITE}
            alt="MedCloud"
            className="w-[320px] max-w-[70%] h-auto object-contain"
          />
        </div>

        {/* Bottom: A Cosentus Division — white text on blue */}
        <div className="pb-10">
          <p className="text-center">
            <span className="text-white/70 text-[14px] font-normal tracking-wide">A </span>
            <span className="text-white/90 text-[18px] font-black tracking-wider uppercase">Cosentus</span>
            <span className="text-white/70 text-[14px] font-normal tracking-wide"> Division</span>
          </p>
        </div>
      </div>
    </div>
  )
}
